-- Agregar columna investorPercentage
ALTER TABLE investor_payouts ADD COLUMN IF NOT EXISTS investorPercentage INT DEFAULT 80 NOT NULL;

-- Agregar columnas de información bancaria
ALTER TABLE investor_payouts ADD COLUMN IF NOT EXISTS bankName VARCHAR(100);
ALTER TABLE investor_payouts ADD COLUMN IF NOT EXISTS bankAccount VARCHAR(100);
ALTER TABLE investor_payouts ADD COLUMN IF NOT EXISTS accountHolder VARCHAR(255);
ALTER TABLE investor_payouts ADD COLUMN IF NOT EXISTS accountType VARCHAR(50);

-- Agregar columna status (renombrar payment_status a status)
ALTER TABLE investor_payouts CHANGE COLUMN payment_status status ENUM('PENDING', 'REQUESTED', 'APPROVED', 'PROCESSING', 'PAID', 'REJECTED') DEFAULT 'PENDING' NOT NULL;

-- Agregar columnas de timestamps
ALTER TABLE investor_payouts ADD COLUMN IF NOT EXISTS requestedAt TIMESTAMP NULL;
ALTER TABLE investor_payouts ADD COLUMN IF NOT EXISTS approvedAt TIMESTAMP NULL;
ALTER TABLE investor_payouts ADD COLUMN IF NOT EXISTS approvedBy INT NULL;

-- Agregar columnas de notas
ALTER TABLE investor_payouts ADD COLUMN IF NOT EXISTS investorNotes TEXT;
ALTER TABLE investor_payouts ADD COLUMN IF NOT EXISTS adminNotes TEXT;
ALTER TABLE investor_payouts ADD COLUMN IF NOT EXISTS rejectionReason TEXT;

